"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[34044],{48061:e=>{e.exports=JSON.parse('{"tag":{"label":"fuel","permalink":"/dst-api-webdocs/docs/tags/fuel","allTagsPath":"/dst-api-webdocs/docs/tags","count":70,"items":[{"id":"game-scripts/prefabs/armor_skeleton","title":"Armor Skeleton","description":"Grants the wearer temporary resistance to multiple damage types by consuming nightmare fuel and spawning visual shield effects when damaged.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_skeleton"},{"id":"game-scripts/prefabs/armor_slurper","title":"Armor Slurper","description":"A wearable inventory item that reduces the owner\'s hunger burn rate while consuming its own fuel over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_slurper"},{"id":"game-scripts/prefabs/balloonvest","title":"Balloonvest","description":"An equippable body-slot item that provides buoyancy and floats on water while consuming magical fuel over time; popping a balloon on the vest interrupts swimming immersion and prevents drowning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloonvest"},{"id":"game-scripts/prefabs/bathbomb","title":"Bathbomb","description":"A consumable item that provides fuel and can be burned, featuring perishable behavior and inventory compatibility.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bathbomb"},{"id":"game-scripts/prefabs/beardhair","title":"Beardhair","description":"A small, stackable inventory item that serves as fuel and decorative snowman accessory, commonly used for campfire refueling and seasonal builds.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beardhair"},{"id":"game-scripts/prefabs/beefalowool","title":"Beefalowool","description":"A single stackable wool item that functions as fuel, a cat toy, and a burnable item in the DST game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefalowool"},{"id":"game-scripts/prefabs/boards","title":"Boards","description":"A stackable inventory item used for repairing boats and as fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boards"},{"id":"game-scripts/prefabs/carnival_prizeticket","title":"Carnival Prizeticket","description":"A stackable, floatable inventory item that serves as a consumable fuel source and cat toy in DST, dynamically adjusting its animation and inventory image based on stack size.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_prizeticket"},{"id":"game-scripts/prefabs/carnival_vest","title":"Carnival Vest","description":"A wearable item that provides seasonal insulation and self-consuming fuel for protection, with dynamic animation overrides while equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_vest"},{"id":"game-scripts/prefabs/charcoal","title":"Charcoal","description":"A stackable consumable item that serves as fuel, food, bait, and a\u88c5\u9970 item in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/charcoal"},{"id":"game-scripts/prefabs/coldfire","title":"Coldfire","description":"Manages the behavior and fuel dynamics of the cold fire structure, including burning, extinguishing, and fuel consumption modified by rain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/coldfire"},{"id":"game-scripts/prefabs/coldfirepit","title":"Coldfirepit","description":"Manages the cold fire pit structure, a weather-resistant campfire that consumes fuel at a variable rate depending on precipitation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/coldfirepit"},{"id":"game-scripts/prefabs/compost","title":"Compost","description":"Provides a deployable, burnable compost item that acts as a fertilizer with defined nutrient content and fuel properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/compost"},{"id":"game-scripts/prefabs/cotl_tabernacle","title":"Cotl Tabernacle","description":"Manages the lifecycle, fueling, burning, and upgrade progression of the Cotl Tabernacle campfire entity across three tiers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cotl_tabernacle"},{"id":"game-scripts/prefabs/cutgrass","title":"Cutgrass","description":"A small, renewable grass item that serves as food, fuel, and repair material for entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutgrass"},{"id":"game-scripts/prefabs/cutreeds","title":"Cutreeds","description":"A stackable, edible inventory item that serves as lightweight fuel and raw vegetation food.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutreeds"},{"id":"game-scripts/components/decay","title":"Decay","description":"Manages a consumable fuel meter that decays over time and triggers events when fuel is spent or added.","permalink":"/dst-api-webdocs/docs/game-scripts/components/decay"},{"id":"game-scripts/prefabs/decor_lamp","title":"Decor Lamp","description":"A decorative lantern prefab that provides adjustable ambient light and consumes cave fuel when active.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/decor_lamp"},{"id":"game-scripts/prefabs/driftwood","title":"Driftwood","description":"A simple wood item that serves as fuel, edible material, repair resource, and waterproofer with zero effectiveness unless modified.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/driftwood"},{"id":"game-scripts/prefabs/featherpencil","title":"Featherpencil","description":"A consumable cat toy that breaks when drawn with and can be used as low-value fuel or igniter.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/featherpencil"},{"id":"game-scripts/prefabs/firenettles","title":"Firenettles","description":"A consumable vegetable item that applies a temporary temperature-based debuff to non-plantkin eaters, which can be dried to produce a longer-lasting fuel source.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firenettles"},{"id":"game-scripts/components/fueled","title":"Fueled","description":"Manages fuel consumption, storage, and state transitions for entities that consume fuel over time.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fueled"},{"id":"game-scripts/components/fueler","title":"Fueler","description":"Tracks and manages the fuel properties and consumption behavior of an entity within the game\'s burning system.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fueler"},{"id":"game-scripts/components/fuelmaster","title":"Fuelmaster","description":"Manages fuel-burning multiplier bonuses for entities that consume fuel, such as fire sources or lanterns.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fuelmaster"},{"id":"game-scripts/prefabs/furtuft","title":"Furtuft","description":"A consumable/loot item that disappears over time when dropped on the ground but stops decaying when placed in an inventory slot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/furtuft"},{"id":"game-scripts/prefabs/glommerfuel","title":"Glommerfuel","description":"A multipurpose item component that functions as fuel, fertilizer, and consumable food in DST, with research support and deployable fertilizer capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glommerfuel"},{"id":"game-scripts/prefabs/glommerwings","title":"Glommerwings","description":"A consumable item that provides medium-large fuel value and functions as burnable/propagator with hauntable properties in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glommerwings"},{"id":"game-scripts/prefabs/goose_feather","title":"Goose Feather","description":"A lightweight decorative item used as a cat toy and small fuel source in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/goose_feather"},{"id":"game-scripts/prefabs/guano","title":"Guano","description":"A consumable and deployable item that acts as a high-value fertilizer and fuel, spawning fly companions when dropped and producing a poison cloud when burned or used as fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/guano"},{"id":"game-scripts/prefabs/halloween_ornaments","title":"Halloween Ornaments","description":"Generates prefab instances for Halloween-themed decorative inventory items with floatable physics and limited fuel value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/halloween_ornaments"},{"id":"game-scripts/prefabs/leif_idol","title":"Leif Idol","description":"A combustible fuel item that, when ignited or consumed as fuel, wakes nearby sleeping Leif entities and spawns new Leif entities from eligible nearby trees.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/leif_idol"},{"id":"game-scripts/components/lighter","title":"Lighter","description":"Enables an entity to ignite burnable targets by calling Ignite on their burnable component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lighter"},{"id":"game-scripts/prefabs/livinglog","title":"Livinglog","description":"A consumable and repair item that emits a sound effect when taken as fuel or ignited.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/livinglog"},{"id":"game-scripts/prefabs/log","title":"Log","description":"A stackable, edible wood item that serves as fuel, repair material, and trash food in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/log"},{"id":"game-scripts/prefabs/malbatross_feathered_weave","title":"Malbatross Feathered Weave","description":"A consumable fuel item that floats on water and burns slowly, used for campfires and cooking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/malbatross_feathered_weave"},{"id":"game-scripts/prefabs/mast","title":"Mast","description":"Manages mast structures for boats, including sail deployment, fuel-powered lighting upgrades (lamp), lightning rod upgrades, and destruction behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mast"},{"id":"game-scripts/prefabs/miniboatlantern","title":"Miniboatlantern","description":"A portable magical lantern that provides light, boosts wearer movement speed, and consumes magic fuel over time while active.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/miniboatlantern"},{"id":"game-scripts/prefabs/minifan","title":"Minifan","description":"A wearable cooling device that consumes fuel to reduce endothermic heat while the player moves and stops cooling when idle or out of fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/minifan"},{"id":"game-scripts/prefabs/mininglantern","title":"Mininglantern","description":"Manages the behavior, lighting, fuel consumption, and equip/unequip interactions for the Mining Lantern item.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mininglantern"},{"id":"game-scripts/components/moonsparkchargeable","title":"Moonsparkchargeable","description":"Increases the fuel level of an entity\'s Fueled component when triggered, based on a configured charge amount.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moonsparkchargeable"},{"id":"game-scripts/prefabs/mosquitofertalizer","title":"Mosquitofertalizer","description":"A portable fertilizer item that provides moderate soil nutrients and repels flies when held, with unique behavior when deployed by a Wurt-activated skill.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitofertalizer"},{"id":"game-scripts/prefabs/mosquitosack","title":"Mosquitosack","description":"A consumable inventory item that heals the user and repairs items while also acting as a combustible fuel source.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitosack"},{"id":"game-scripts/prefabs/nightmarefuel","title":"Nightmarefuel","description":"Implements a consumable item used as high-value fuel, repair material, and waterproofer in DST, with networked animation state and stacking support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmarefuel"},{"id":"game-scripts/prefabs/nitre","title":"Nitre","description":"A small elemental item used as fuel, bait, and food, primarily for attracting moles and fueling campfires.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nitre"},{"id":"game-scripts/prefabs/nonslipgrit","title":"Nonslipgrit","description":"Applies a temporary non-slip buff to entities while consuming fuel over time, optionally spawning ice pools when boosted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nonslipgrit"},{"id":"game-scripts/prefabs/palmcone_scale","title":"Palmcone Scale","description":"A consumable fuel item used for campfires and related ignition sources, providing moderate fuel value and burn duration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/palmcone_scale"},{"id":"game-scripts/prefabs/papyrus","title":"Papyrus","description":"A small, stackable cat toy item that can be used as fuel and consumed in campfires or by fire-based entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/papyrus"},{"id":"game-scripts/prefabs/pigtorch","title":"Pigtorch","description":"A structure that produces guards and burns fuel over time, extinguishing when its fuel runs out or during rain.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigtorch"},{"id":"game-scripts/prefabs/pocketwatch_weapon","title":"Pocketwatch Weapon","description":"A weaponized pocketwatch that toggles between shadow and depleted states based on fuel level, altering damage and emitting visual effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pocketwatch_weapon"},{"id":"game-scripts/prefabs/poop","title":"Poop","description":"A consumable and deployable item that acts as a fertilizer, fuel, and ignitable object, spawning flies when dropped and releasing a cloud upon fueling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/poop"},{"id":"game-scripts/prefabs/portablefirepit","title":"Portablefirepit","description":"Manages the portable firepit item and its deployed state, handling fuel consumption, ignition, dismantling, and charcoal production logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/portablefirepit"},{"id":"game-scripts/prefabs/redlantern","title":"Redlantern","description":"A magical lantern that emits light and consumes fuel over time; supports equipping, rain exposure handling, and dynamic visual effects via attached child entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/redlantern"},{"id":"game-scripts/prefabs/reflectivevest","title":"Reflectivevest","description":"A wearable item that provides insulation, water resistance, and fuel-based active protection, worn on the body slot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/reflectivevest"},{"id":"game-scripts/prefabs/rope","title":"Rope","description":"A simple consumable item used as fuel, tradable as a cat toy, and flammable in the environment.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rope"},{"id":"game-scripts/prefabs/spidereggsack","title":"Spidereggsack","description":"A deployable item that spawns a spider den when placed, used as bait or a resource.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spidereggsack"},{"id":"game-scripts/prefabs/steelwool","title":"Steelwool","description":"A small, stackable fuel item that provides moderate burn duration and ignites easily when exposed to fire or heat sources.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/steelwool"},{"id":"game-scripts/prefabs/storage_robot","title":"Storage Robot","description":"Manages the behavior and state of the Storage Robot, a companion entity that collects and stores items from the world using fuel-based operation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/storage_robot"},{"id":"game-scripts/prefabs/sweatervest","title":"Sweatervest","description":"Provides insulation and temporary heat protection when equipped, depleting fuel over time while worn.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sweatervest"},{"id":"game-scripts/prefabs/tentaclespots","title":"Tentaclespots","description":"A small fuel item used to power burnable structures and devices in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tentaclespots"},{"id":"game-scripts/prefabs/thurible","title":"Thurible","description":"Manages the behavior and state of the Thurible item, a lantern that lights up in the Dark and attracts Shadow Creatures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/thurible"},{"id":"game-scripts/prefabs/torch","title":"Torch","description":"Manages the torch item\u2019s lighting, fuel consumption, ignited state, and interaction with Wilson\u2019s skilltree upgrades.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torch"},{"id":"game-scripts/prefabs/turfs","title":"Turfs","description":"Generates prefabs for ground tile items that can be placed on the map to replace existing tiles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/turfs"},{"id":"game-scripts/prefabs/twigs","title":"Twigs","description":"A multi-functional small item that serves as fuel, food, repair material, and ocean fishing tackle in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/twigs"},{"id":"game-scripts/prefabs/walking_stick","title":"Walking Stick","description":"Manages equippable item behavior for the Walking Stick, including fuel consumption based on owner movement and animation overrides.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/walking_stick"},{"id":"game-scripts/prefabs/waterplant_planter","title":"Waterplant Planter","description":"A stackable inventory item that serves as a specialized fuel source and can be upgraded via the waterplant planter upgrade type.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterplant_planter"},{"id":"game-scripts/prefabs/waxpaper","title":"Waxpaper","description":"A small item that serves as light fuel and can ignite nearby flammable objects when exposed to heat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waxpaper"},{"id":"game-scripts/prefabs/waxwelljournal","title":"Waxwelljournal","description":"A magical spellbook prefab used by shadow magic users that manages spellcasting, fuel consumption, sanity impact, and minion spawning through its components and sound-driven idle behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waxwelljournal"},{"id":"game-scripts/prefabs/winona_battery_low","title":"Winona Battery Low","description":"Manages low-capacity energy storage, fuel consumption, circuit integration, and elemental fuel type handling for Winona\'s battery structure in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_battery_low"},{"id":"game-scripts/prefabs/winter_ornaments","title":"Winter Ornaments","description":"Defines and instantiates all winter ornament prefabs as consumable inventory items with optional lighting, timer, and fuel mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winter_ornaments"},{"id":"game-scripts/prefabs/yotb_pattern_fragments","title":"Yotb Pattern Fragments","description":"A set of three throwable pattern fragment items that serve as fuel and cat toys.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotb_pattern_fragments"}],"unlisted":false}}')}}]);